274→		cclog.Errorf("WEB/WEB > template '%s' not found", file)
275→	}
276→
277→	if page.Clusters == nil {
278→		page.Clusters = make([]string, 0)
279→	}
280→
281→	if page.SubClusters == nil {
282→		page.SubClusters = make(map[string][]string)
283→		for _, cluster := range archive.Clusters {
